"""
Pytest test suite for the requirement:
"A clinician shall record a Procedure tied to an Encounter."

Covers:
- Happy-path recording
- Permission / role denial
- Missing mandatory elements
- Conflicting state transitions
- Edge cases (duplicate, cancelled encounter, unknown encounter, etc.)
"""

import pytest
from datetime import datetime, timedelta
from unittest.mock import MagicMock, patch, PropertyMock
from uuid import uuid4

# ---------------------------------------------------------------------------
# Domain models / service layer (thin stubs so the tests are self-contained)
# These would normally be imported from your application package.
# ---------------------------------------------------------------------------

class PermissionError(Exception):
    pass


class ValidationError(Exception):
    pass


class StateConflictError(Exception):
    pass


class NotFoundError(Exception):
    pass


class DuplicateError(Exception):
    pass


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------

@pytest.fixture()
def clinician_user():
    """A user with the 'clinician' role."""
    user = MagicMock()
    user.id = str(uuid4())
    user.role = "clinician"
    user.has_permission = MagicMock(return_value=True)
    return user


@pytest.fixture()
def nurse_user():
    """A user with 'nurse' role – can view but NOT record procedures."""
    user = MagicMock()
    user.id = str(uuid4())
    user.role = "nurse"
    user.has_permission = MagicMock(return_value=False)
    return user


@pytest.fixture()
def admin_user():
    """An administrative user with no clinical write permissions."""
    user = MagicMock()
    user.id = str(uuid4())
    user.role = "admin"
    user.has_permission = MagicMock(return_value=False)
    return user


@pytest.fixture()
def active_encounter():
    """An encounter in 'in-progress' state."""
    encounter = MagicMock()
    encounter.id = str(uuid4())
    encounter.status = "in-progress"
    encounter.patient_id = str(uuid4())
    encounter.start_time = datetime.utcnow() - timedelta(hours=1)
    encounter.end_time = None
    return encounter


@pytest.fixture()
def finished_encounter():
    """An encounter in 'finished' state."""
    encounter = MagicMock()
    encounter.id = str(uuid4())
    encounter.status = "finished"
    encounter.patient_id = str(uuid4())
    encounter.start_time = datetime.utcnow() - timedelta(hours=3)
    encounter.end_time = datetime.utcnow() - timedelta(hours=1)
    return encounter


@pytest.fixture()
def cancelled_encounter():
    """An encounter that was cancelled."""
    encounter = MagicMock()
    encounter.id = str(uuid4())
    encounter.status = "cancelled"
    encounter.patient_id = str(uuid4())
    return encounter


@pytest.fixture()
def valid_procedure_payload(active_encounter, clinician_user):
    """Minimal valid payload for recording a procedure."""
    return {
        "encounter_id": active_encounter.id,
        "patient_id": active_encounter.patient_id,
        "code": "80146002",          # SNOMED CT – Appendectomy
        "display": "Appendectomy",
        "status": "completed",
        "performed_at": datetime.utcnow().isoformat(),
        "recorded_by": clinician_user.id,
    }


@pytest.fixture()
def procedure_service(active_encounter, finished_encounter, cancelled_encounter):
    """
    A mock of the ProcedureService that enforces the domain rules we are testing.
    In a real project this would be the actual service under test; here we
    replicate just enough behaviour to make every assertion meaningful.
    """
    service = MagicMock()

    def _record_procedure(payload: dict, requesting_user):
        # 1. Permission check
        if not requesting_user.has_permission("procedure:write"):
            raise PermissionError(
                f"User role '{requesting_user.role}' lacks procedure:write permission."
            )

        # 2. Mandatory field validation
        required_fields = ["encounter_id", "patient_id", "code", "status", "performed_at"]
        missing = [f for f in required_fields if not payload.get(f)]
        if missing:
            raise ValidationError(f"Missing mandatory fields: {missing}")

        # 3. Encounter lookup
        encounter_lookup = {
            active_encounter.id: active_encounter,
            finished_encounter.id: finished_encounter,
            cancelled_encounter.id: cancelled_encounter,
        }
        enc = encounter_lookup.get(payload["encounter_id"])
        if enc is None:
            raise NotFoundError(
                f"Encounter '{payload['encounter_id']}' not found."
            )

        # 4. State transition guard – procedure can only be added to an
        #    in-progress or (for documentation purposes) a finished encounter.
        if enc.status == "cancelled":
            raise StateConflictError(
                f"Cannot record a procedure against a cancelled encounter "
                f"(encounter id: {enc.id})."
            )

        # 5. Status value guard
        valid_statuses = {"preparation", "in-progress", "not-done", "on-hold",
                          "stopped", "completed", "entered-in-error", "unknown"}
        if payload["status"] not in valid_statuses:
            raise ValidationError(
                f"Invalid procedure status '{payload['status']}'."
            )

        # 6. Patient coherence check
        if payload.get("patient_id") != enc.patient_id:
            raise ValidationError(
                "patient_id in payload does not match the encounter's patient."
            )

        # 7. Performed-at must not be in the future
        performed_at = datetime.fromisoformat(payload["performed_at"])
        if performed_at > datetime.utcnow() + timedelta(seconds=5):
            raise ValidationError("performed_at cannot be a future timestamp.")

        # 8. Build and return a stub procedure record
        procedure = MagicMock()
        procedure.id = str(uuid4())
        procedure.encounter_id = payload["encounter_id"]
        procedure.patient_id = payload["patient_id"]
        procedure.code = payload["code"]
        procedure.status = payload["status"]
        procedure.performed_at = payload["performed_at"]
        procedure.recorded_by = payload.get("recorded_by")
        return procedure

    service.record_procedure = MagicMock(side_effect=_record_procedure)
    return service


# ===========================================================================
# HAPPY-PATH TESTS
# ===========================================================================

class TestRecordProcedureHappyPath:

    def test_clinician_records_procedure_on_active_encounter(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """Core success case: a clinician records a completed procedure."""
        result = procedure_service.record_procedure(
            valid_procedure_payload, clinician_user
        )

        assert result is not None
        assert result.encounter_id == valid_procedure_payload["encounter_id"]
        assert result.code == valid_procedure_payload["code"]
        assert result.status == "completed"
        assert result.recorded_by == clinician_user.id

    def test_procedure_linked_to_correct_encounter(
        self, procedure_service, valid_procedure_payload, clinician_user, active_encounter
    ):
        """Returned procedure must reference the submitted encounter."""
        result = procedure_service.record_procedure(
            valid_procedure_payload, clinician_user
        )
        assert result.encounter_id == active_encounter.id

    def test_procedure_linked_to_correct_patient(
        self, procedure_service, valid_procedure_payload, clinician_user, active_encounter
    ):
        """Returned procedure must reference the encounter's patient."""
        result = procedure_service.record_procedure(
            valid_procedure_payload, clinician_user
        )
        assert result.patient_id == active_encounter.patient_id

    def test_record_procedure_on_finished_encounter(
        self,
        procedure_service,
        valid_procedure_payload,
        clinician_user,
        finished_encounter,
    ):
        """Clinicians may add a late-documentation procedure to a finished encounter."""
        payload = {
            **valid_procedure_payload,
            "encounter_id": finished_encounter.id,
            "patient_id": finished_encounter.patient_id,
        }
        result = procedure_service.record_procedure(payload, clinician_user)
        assert result.encounter_id == finished_encounter.id

    def test_procedure_status_in_progress(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """A procedure with status 'in-progress' should be accepted."""
        payload = {**valid_procedure_payload, "status": "in-progress"}
        result = procedure_service.record_procedure(payload, clinician_user)
        assert result.status == "in-progress"

    def test_procedure_status_not_done(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """A procedure explicitly marked 'not-done' should be accepted."""
        payload = {**valid_procedure_payload, "status": "not-done"}
        result = procedure_service.record_procedure(payload, clinician_user)
        assert result.status == "not-done"

    def test_record_procedure_returns_unique_id(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """Each recorded procedure must receive a unique identifier."""
        result1 = procedure_service.record_procedure(
            valid_procedure_payload, clinician_user
        )
        result2 = procedure_service.record_procedure(
            valid_procedure_payload, clinician_user
        )
        assert result1.id != result2.id

    def test_service_called_with_correct_arguments(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """Verify the service is invoked with exactly the payload we supplied."""
        procedure_service.record_procedure(valid_procedure_payload, clinician_user)
        procedure_service.record_procedure.assert_called_once_with(
            valid_procedure_payload, clinician_user
        )


# ===========================================================================
# PERMISSION / ROLE DENIAL TESTS
# ===========================================================================

class TestRecordProcedurePermissionDenial:

    def test_nurse_cannot_record_procedure(
        self, procedure_service, valid_procedure_payload, nurse_user
    ):
        """A nurse does not have procedure:write and must be denied."""
        with pytest.raises(PermissionError, match="procedure:write"):
            procedure_service.record_procedure(valid_procedure_payload, nurse_user)

    def test_admin_cannot_record_procedure(
        self, procedure_service, valid_procedure_payload, admin_user
    ):
        """An admin user must be denied clinical write access."""
        with pytest.raises(PermissionError):
            procedure_service.record_procedure(valid_procedure_payload, admin_user)

    def test_unauthenticated_user_cannot_record_procedure(
        self, procedure_service, valid_procedure_payload
    ):
        """An anonymous / unauthenticated caller must be denied."""
        anonymous = MagicMock()
        anonymous.role = "anonymous"
        anonymous.has_permission = MagicMock(return_value=False)

        with pytest.raises(PermissionError):
            procedure_service.record_procedure(valid_procedure_payload, anonymous)

    def test_permission_error_message_includes_role(
        self, procedure_service, valid_procedure_payload, nurse_user
    ):
        """The permission error should name the offending role for auditability."""
        with pytest.raises(PermissionError, match="nurse"):
            procedure_service.record_procedure(valid_procedure_payload, nurse_user)

    def test_revoked_clinician_permission_is_denied(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """Even a clinician whose permission was explicitly revoked must be blocked."""
        clinician_user.has_permission = MagicMock(return_value=False)
        with pytest.raises(PermissionError):
            procedure_service.record_procedure(valid_procedure_payload, clinician_user)


# ===========================================================================
# MISSING MANDATORY ELEMENTS TESTS
# ===========================================================================

class TestRecordProcedureMissingMandatoryElements:

    @pytest.mark.parametrize("missing_field", [
        "encounter_id",
        "patient_id",
        "code",
        "status",
        "performed_at",
    ])
    def test_missing_mandatory_field_raises_validation_error(
        self, procedure_service, valid_procedure_payload, clinician_user, missing_field
    ):
        """Omitting any mandatory field must raise ValidationError."""
        payload = {**valid_procedure_payload}
        del payload[missing_field]

        with pytest.raises(ValidationError, match=missing_field):
            procedure_service.record_procedure(payload, clinician_user)

    def test_empty_string_encounter_id_is_rejected(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """An empty encounter_id is logically equivalent to missing."""
        payload = {**valid_procedure_payload, "encounter_id": ""}
        with pytest.raises(ValidationError):
            procedure_service.record_procedure(payload, clinician_user)

    def test_empty_string_code_is_rejected(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """A blank clinical code has no meaning and must be rejected."""
        payload = {**valid_procedure_payload, "code": ""}
        with pytest.raises(ValidationError):
            procedure_service.record_procedure(payload, clinician_user)

    def test_none_performed_at_is_rejected(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """performed_at=None must be treated as missing."""
        payload = {**valid_procedure_payload, "performed_at": None}
        with pytest.raises(ValidationError):
            procedure_service.record_procedure(payload, clinician_user)

    def test_empty_payload_raises_validation_error(
        self, procedure_service, clinician_user
    ):
        """Submitting a completely empty payload must list all missing fields."""
        with pytest.raises(ValidationError):
            procedure_service.record_procedure({}, clinician_user)

    def test_invalid_procedure_status_raises_validation_error(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """An unrecognised status value must be rejected."""
        payload = {**valid_procedure_payload, "status": "INVALID_STATUS"}
        with pytest.raises(ValidationError, match="INVALID_STATUS"):
            procedure_service.record_procedure(payload, clinician_user)

    def test_patient_mismatch_raises_validation_error(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """patient_id in the payload must match the encounter's patient."""
        payload = {**valid_procedure_payload, "patient_id": str(uuid4())}
        with pytest.raises(ValidationError, match="patient_id"):
            procedure_service.record_procedure(payload, clinician_user)

    def test_future_performed_at_is_rejected(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """A procedure timestamp in the future is clinically invalid."""
        future = (datetime.utcnow() + timedelta(hours=2)).isoformat()
        payload = {**valid_procedure_payload, "performed_at": future}
        with pytest.raises(ValidationError, match="future"):
            procedure_service.record_procedure(payload, clinician_user)


