class TestRecordProcedureConflictingStateTransitions:

    def test_procedure_against_cancelled_encounter_raises_state_conflict(
        self,
        procedure_service,
        valid_procedure_payload,
        clinician_user,
        cancelled_encounter,
    ):
        """Adding a procedure to a cancelled encounter must raise StateConflictError."""
        payload = {
            **valid_procedure_payload,
            "encounter_id": cancelled_encounter.id,
            "patient_id": cancelled_encounter.patient_id,
        }
        with pytest.raises(StateConflictError, match="cancelled"):
            procedure_service.record_procedure(payload, clinician_user)

    def test_state_conflict_error_references_encounter_id(
        self,
        procedure_service,
        valid_procedure_payload,
        clinician_user,
        cancelled_encounter,
    ):
        """The StateConflictError message must include the offending encounter id."""
        payload = {
            **valid_procedure_payload,
            "encounter_id": cancelled_encounter.id,
            "patient_id": cancelled_encounter.patient_id,
        }
        with pytest.raises(StateConflictError, match=cancelled_encounter.id):
            procedure_service.record_procedure(payload, clinician_user)

    def test_nonexistent_encounter_raises_not_found(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """Referencing an encounter that does not exist must raise NotFoundError."""
        payload = {**valid_procedure_payload, "encounter_id": str(uuid4())}
        with pytest.raises(NotFoundError):
            procedure_service.record_procedure(payload, clinician_user)

    def test_not_found_error_includes_encounter_id(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """NotFoundError should identify which encounter was missing."""
        missing_id = str(uuid4())
        payload = {**valid_procedure_payload, "encounter_id": missing_id}
        with pytest.raises(NotFoundError, match=missing_id):
            procedure_service.record_procedure(payload, clinician_user)

    def test_procedure_status_entered_in_error_is_accepted(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """'entered-in-error' is a valid FHIR status and must not be blocked."""
        payload = {**valid_procedure_payload, "status": "entered-in-error"}
        result = procedure_service.record_procedure(payload, clinician_user)
        assert result.status == "entered-in-error"

    def test_permission_checked_before_state(
        self, procedure_service, valid_procedure_payload, nurse_user, cancelled_encounter
    ):
        """
        Permission denial should surface before state-conflict validation.
        This ensures we do not leak encounter state to unauthorised callers.
        """
        payload = {
            **valid_procedure_payload,
            "encounter_id": cancelled_encounter.id,
            "patient_id": cancelled_encounter.patient_id,
        }
        with pytest.raises(PermissionError):
            procedure_service.record_procedure(payload, nurse_user)

    def test_validation_checked_before_encounter_lookup(
        self, procedure_service, clinician_user
    ):
        """
        Mandatory-field validation should surface before encounter lookup,
        preventing unnecessary database calls with garbage input.
        """
        incomplete_payload = {
            "encounter_id": str(uuid4()),
            # missing: patient_id, code, status, performed_at
        }
        with pytest.raises(ValidationError):
            procedure_service.record_procedure(incomplete_payload, clinician_user)


