class TestRecordProcedureEdgeCases:

    def test_recording_multiple_procedures_on_same_encounter_is_allowed(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """
        Multiple distinct procedures may be recorded against a single encounter
        (e.g. a procedure and an incidental finding procedure).
        """
        payload_1 = {**valid_procedure_payload, "code": "80146002"}
        payload_2 = {**valid_procedure_payload, "code": "173171007"}

        result_1 = procedure_service.record_procedure(payload_1, clinician_user)
        result_2 = procedure_service.record_procedure(payload_2, clinician_user)

        assert result_1.id != result_2.id
        assert result_1.encounter_id == result_2.encounter_id

    def test_service_called_twice_for_two_procedures(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """Service should register exactly two invocations for two procedures."""
        procedure_service.record_procedure(valid_procedure_payload, clinician_user)
        procedure_service.record_procedure(valid_procedure_payload, clinician_user)
        assert procedure_service.record_procedure.call_count == 2

    def test_procedure_payload_is_not_mutated_by_service(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """The service must not mutate the caller's payload dict."""
        original_payload = dict(valid_procedure_payload)
        procedure_service.record_procedure(valid_procedure_payload, clinician_user)
        assert valid_procedure_payload == original_payload

    def test_whitespace_only_code_is_rejected(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """A code consisting entirely of whitespace is semantically empty."""
        payload = {**valid_procedure_payload, "code": "   "}
        # The service stub treats falsy strings as missing
        with pytest.raises((ValidationError, ValueError)):
            procedure_service.record_procedure(payload, clinician_user)

    def test_sql_injection_in_encounter_id_raises_not_found(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """Malicious input in encounter_id should not cause unexpected behaviour."""
        payload = {
            **valid_procedure_payload,
            "encounter_id": "' OR '1'='1",
        }
        with pytest.raises(NotFoundError):
            procedure_service.record_procedure(payload, clinician_user)

    def test_very_long_display_text_does_not_raise(
        self, procedure_service, valid_procedure_payload, clinician_user
    ):
        """Unusually long display text should not crash the service (truncation is fine)."""
        payload = {**valid_procedure_payload, "display": "A" * 10_000}
        # Should succeed without an exception (service may truncate internally)
        result = procedure_service.record_procedure(payload, clinician_user)
        assert result is not None

    @pytest.mark.parametrize("status", [
        "preparation", "in-progress", "not-done",
        "on-hold", "stopped", "completed", "entered-in-error", "unknown",
    ])
    def test_all_valid_fhir_procedure_statuses_are_accepted(
        self, procedure_service, valid_procedure_payload, clinician_user, status
    ):
        """Every status value defined by FHIR R4 must be accepted."""
        payload = {**valid_procedure_payload, "status": status}
        result = procedure_service.record_procedure(payload, clinician_user)
        assert result.status == status
